code = """import json, pandas as pd, re

# Load data from files
civic_file = locals()['var_functions.query_db:2']
with open(civic_file) as f:
    civic_docs = json.load(f)

funding_data = locals()['var_functions.query_db:24']
funding_df = pd.DataFrame(funding_data)
funding_df['Amount'] = pd.to_numeric(funding_df['Amount'], errors='coerce')

# Find disaster projects starting in 2022 from civic documents
disaster_2022 = []

for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    for i in range(len(lines)):
        line = lines[i].strip()
        # Check for disaster keywords
        if 'FEMA' in line or 'CalOES' in line or 'CalJPIA' in line or 'disaster' in line.lower():
            # Look for project name in previous lines
            proj_name = None
            for j in range(i-1, max(-1, i-5), -1):
                prev = lines[j].strip()
                if len(prev) > 10 and len(prev.split()) >= 3:
                    proj_name = prev
                    break
            if proj_name:
                # Check for 2022 start date in nearby lines
                has_2022_start = False
                window = lines[max(0, i-3):min(len(lines), i+8)]
                for w_line in window:
                    if '2022' in w_line and any(word in w_line.lower() for word in ['begin', 'start', 'design', 'construction']):
                        has_2022_start = True
                        break
                if has_2022_start:
                    disaster_2022.append({'Project_Name': proj_name})

# Remove duplicates
projects_df = pd.DataFrame(disaster_2022).drop_duplicates()
print('Found', len(projects_df), 'unique disaster projects starting 2022')

# Match with funding data
total_funding = 0.0
matched = 0

for _, proj in projects_df.iterrows():
    p_name = proj['Project_Name'].lower()
    for _, fnd in funding_df.iterrows():
        f_name = fnd['Project_Name'].lower()
        # Check if names match
        if p_name in f_name or f_name in p_name or any(word in f_name for word in p_name.split()[:3]):
            total_funding += fnd['Amount']
            matched += 1
            # Remove to avoid double counting
            funding_df = funding_df[funding_df.index != fnd.name]
            break

result = {'total_funding': float(total_funding), 'projects_matched': matched}
print('Result:', result)
__RESULT__: json.dumps(result)"""

